// Mirrors gofa-egm-python's nudge_joint.py: capture the pose on the
// first feedback frame as baseline, then offset one joint with a smooth
// sine so it returns to baseline on its own every 8s. Baseline/start are
// stored in this node's own context, captured once per Node-RED restart
// or redeploy (context is cleared then) -- re-pressing "Start EGM" after
// a "Stop EGM" without redeploying resumes the same sweep rather than
// re-baselining, which is fine for this demo.
var joints = msg.payload && msg.payload.joints;
if (!Array.isArray(joints) || joints.length !== 6) return null;

if (context.get('baseline') === undefined) {
    context.set('baseline', joints);
    context.set('start', Date.now());
}

var baseline = context.get('baseline');
var elapsed = (Date.now() - context.get('start')) / 1000;
var target = baseline.slice();
target[5] = target[5] + 3 * Math.sin(2 * Math.PI * elapsed / 8);

msg.payload = target;
return msg;
